import hashlib

def file_hash(filename):
    """Creates a hash of a file for integrity checking.

    Args:
        filename: The path to the file.

    Returns:
        The hash of the file.
    """

    h = hashlib.sha256()
    b = bytearray(128)
    mv = memoryview(b)

    with open(filename, "rb", buffering=0) as f:
        while True:
            n = f.readinto(mv)
            if n == 0:
                break
            h.update(mv[:n])

    return h.hexdigest()